package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testCSVFormat() {
        // Given
        char delimiter = ',';
        Character quoteChar = '"';
        CSVFormat csvFormat = new CSVFormat(delimiter, quoteChar, null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        char actualDelimiter = csvFormat.getDelimiter();
        Character actualQuoteChar = csvFormat.getQuoteCharacter();

        // Then
        assertEquals(delimiter, actualDelimiter);
        assertEquals(quoteChar, actualQuoteChar);
    }

    @Test
    public void testNewFormat() {
        // Given
        char delimiter = ',';

        // When
        CSVFormat csvFormat = CSVFormat.newFormat(delimiter);

        // Then
        assertEquals(delimiter, csvFormat.getDelimiter());
    }

    @Test
    public void testValueOf() {
        // Given
        String format = "DEFAULT";

        // When
        CSVFormat csvFormat = CSVFormat.valueOf(format);

        // Then
        assertNotNull(csvFormat);
    }

    // Add more tests for other methods as needed
}
